export default function r(n,o=n){const e=new Uint8ClampedArray(n*o*4);for(let a=0;a<e.length;)e[a++]=e[a++]=e[a++]=Math.random()*255,e[a++]=255;const m=new ImageData(e,n),t=document.createElement("canvas");return t.width=n,t.height=o,t.getContext("2d").putImageData(m,0,0),t.remove(),t.toDataURL("image/png")}
